import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Вивантаження звітів","description":"Як вивантажити звіти для усунення несправностей.","frontmatter":{"title":"Вивантаження звітів","description":"Як вивантажити звіти для усунення несправностей.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"uk_ua/1.21.1/players/troubleshooting/uploading-logs.md","filePath":"versions/1.21.1/translated/uk_ua/players/troubleshooting/uploading-logs.md","lastUpdated":1761424914000}`);var a={name:`uk_ua/1.21.1/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Вивантаження звітів <a class="header-anchor" href="#h1" aria-label="Permalink to “Вивантаження звітів”">​</a></h1><p>Під час усунення проблем часто необхідно надати журнали, щоб допомогти визначити причину проблеми.</p><h2 id="why-should-i-upload-logs" tabindex="-1">Чому я повинен завантажувати журнали? <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “Чому я повинен завантажувати журнали?”">​</a></h2><p>Завантаження журналів дозволяє іншим допомогти вам розв&#39;язувати ваші проблеми набагато швидше, ніж просто вставляти журнали в чат або повідомлення на форумі. Це також дозволяє вам ділитися своїми журналами з іншими без необхідності копіювати та вставляти їх.</p><p>Деякі сторінки вставлення також надають підсвічування синтаксису для журналів, що полегшує їх читання, і може цензурувати конфіденційну інформацію, таку як ваше ім&#39;я користувача або інформацію про систему.</p><h2 id="crash-reports" tabindex="-1">Звіти про збої <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “Звіти про збої”">​</a></h2><p>Звіти про збої створюються автоматично, коли гра виходить з ладу. Вони містять лише інформацію про збої, а не журнали гри. Вони знаходяться в теці <code>crash-reports</code> в каталозі гри.</p><p>Додаткову інформацію про звіти про збої див. у <a href="./crash-reports">звіти про збої</a>.</p><h2 id="locating-logs" tabindex="-1">Пошук журналів <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “Пошук журналів”">​</a></h2><p>У цьому посібнику описано офіційний запускач Minecraft (зазвичай відомий як «ванілльний запускач») — для програм запуску сторонніх розробників слід ознайомитися з їх документацією.</p><p>Журнали знаходяться в теці <code>logs</code> в каталозі гри, каталог гри можна знайти в таких місцях залежно від вашої операційної системи:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>Останній журнал називається <code>latest.log</code>, а попередні журнали використовують шаблон іменування <code>yyyy-mm-dd_number.log.gz</code>.</p><h2 id="uploading-logs-online" tabindex="-1">Завантаження журналів онлайн <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “Завантаження журналів онлайн”">​</a></h2><p>Звіти можуть бути вивантажені на різноманітні сервіси, таких як:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};